import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.stream.ActorMaterializer
import spray.json._

import scala.concurrent.ExecutionContext.Implicits.global

case class UrlRequest(url: String)

object WebhookProxy extends App {
  implicit val system = ActorSystem("webhook-proxy")
  implicit val materializer = ActorMaterializer()
  import system.dispatcher

  implicit val urlRequestFormat: RootJsonFormat[UrlRequest] = jsonFormat1(UrlRequest)

  val route =
    path("fetch") {
      post {
        entity(as[String]) { requestBody =>
          complete {
            val urlRequest = requestBody.parseJson.convertTo[UrlRequest]
            val userUrl = urlRequest.url

            Http().singleRequest(HttpRequest(uri = userUrl)).flatMap {
              case HttpResponse(status, headers, entity, protocol) =>
                entity.toStrict(10.seconds).map { strictEntity =>
                  HttpResponse(
                    status = status,
                    headers = headers,
                    entity = HttpEntity(ContentTypes.`application/json`, strictEntity.data.utf8String),
                    protocol = protocol
                  )
                }
            }
          }
        }
      }
    }

  val bindingFuture = Http().bindAndHandle(route, "localhost", 8080)
  println(s"Server online at http://localhost:8080/\nPress RETURN to stop...")
  StdIn.readLine() // let it run until user presses return
  bindingFuture.flatMap(_.unbind()).onComplete(_ => system.terminate())
}